{"type": "email", "id": "email_001", "subject": "Weekly Team Meeting Agenda", "from": "rachel.lee@mediconn.com", "from_name": "Rachel Lee", "to": ["michael.johnson@mediconn.com", "lisa.campbell@mediconn.com", "peter.murphy@mediconn.com"], "cc": [], "date": "2026-01-01 10:00:00", "body": "Hello Team,

